(()=>{
  if(window.Chart) return;

  const chartByCanvas = new WeakMap();

  function clamp(v,min,max){ return Math.max(min,Math.min(max,v)); }
  function hexToRgba(color,alpha){
    if(!color) return `rgba(99,102,241,${alpha})`;
    const h=color.replace('#','').trim();
    if(!/^[0-9a-fA-F]{6}$/.test(h)) return color;
    const n=parseInt(h,16);
    return `rgba(${(n>>16)&255},${(n>>8)&255},${n&255},${alpha})`;
  }

  class MiniChart {
    static getChart(canvas){ return chartByCanvas.get(canvas)||null; }

    constructor(ctx,config={}){
      if(!ctx||!ctx.canvas) throw new Error('Chart context is required');
      this.ctx=ctx;
      this.canvas=ctx.canvas;
      this.config=config;
      this.options=config.options||{};
      this.type=config.type||'line';
      this.data=config.data||{labels:[],datasets:[]};
      this.plugins=config.plugins||[];
      this.chartArea={left:28,right:Math.max(28,this.canvas.width-10),top:18,bottom:Math.max(18,this.canvas.height-24)};
      this.tooltip={
        _active:[],
        getActiveElements:()=>this.tooltip._active,
        setActiveElements:(arr)=>{ this.tooltip._active=Array.isArray(arr)?arr:[]; }
      };
      this._activeElements=[];
      this._points=[];
      this._destroyed=false;
      chartByCanvas.set(this.canvas,this);
      this._boundMove=(e)=>this._onMove(e);
      this._boundLeave=()=>this._clearActive();
      this.canvas.addEventListener('mousemove',this._boundMove,{passive:true});
      this.canvas.addEventListener('mouseleave',this._boundLeave,{passive:true});
      this.canvas.addEventListener('touchmove',this._boundMove,{passive:true});
      this.canvas.addEventListener('touchend',this._boundLeave,{passive:true});
      this.resize();
    }

    setActiveElements(arr){
      this._activeElements=Array.isArray(arr)?arr:[];
    }

    destroy(){
      if(this._destroyed) return;
      this._destroyed=true;
      this.canvas.removeEventListener('mousemove',this._boundMove);
      this.canvas.removeEventListener('mouseleave',this._boundLeave);
      this.canvas.removeEventListener('touchmove',this._boundMove);
      this.canvas.removeEventListener('touchend',this._boundLeave);
      chartByCanvas.delete(this.canvas);
    }

    update(){ this._draw(); }

    resize(){
      const rect=this.canvas.getBoundingClientRect();
      const dpr=window.devicePixelRatio||1;
      const width=Math.max(10,Math.round((rect.width||this.canvas.width||300)*dpr));
      const height=Math.max(10,Math.round((rect.height||this.canvas.height||150)*dpr));
      if(this.canvas.width!==width||this.canvas.height!==height){
        this.canvas.width=width;
        this.canvas.height=height;
      }
      this.ctx.setTransform(1,0,0,1,0,0);
      this.ctx.scale(dpr,dpr);
      const logicalW=width/dpr;
      const logicalH=height/dpr;
      this.chartArea={left:28,right:logicalW-10,top:18,bottom:logicalH-24};
      this._draw();
    }

    _dataset(){ return this.data.datasets?.[0]||{data:[]}; }

    _extractValues(){
      const ds=this._dataset();
      const values=(ds.data||[]).map((v)=>typeof v==='number'?v:(v&&typeof v.y==='number'?v.y:NaN)).filter((v)=>Number.isFinite(v));
      return values;
    }

    _coords(){
      const values=this._extractValues();
      const labels=this.data.labels||[];
      const count=values.length;
      if(!count) return [];
      const min=Math.min(...values);
      const max=Math.max(...values);
      const range=(max-min)||1;
      const {left,right,top,bottom}=this.chartArea;
      const w=(right-left)||1;
      const h=(bottom-top)||1;
      return values.map((v,i)=>({
        x:left+(count===1?0.5:(i/(count-1)))*w,
        y:bottom-((v-min)/range)*h,
        value:v,
        label:labels[i]||''
      }));
    }

    _draw(){
      if(this._destroyed) return;
      const ctx=this.ctx;
      const {left,right,top,bottom}=this.chartArea;
      const ds=this._dataset();
      const points=this._coords();
      this._points=points;
      ctx.clearRect(0,0,this.canvas.width,this.canvas.height);
      ctx.save();
      ctx.strokeStyle='rgba(148,163,184,.12)';
      for(let i=0;i<4;i++){
        const y=top+((bottom-top)*(i/3));
        ctx.beginPath();ctx.moveTo(left,y);ctx.lineTo(right,y);ctx.stroke();
      }
      ctx.restore();

      if(!points.length){ this._runPlugins(); return; }

      ctx.save();
      ctx.beginPath();
      points.forEach((p,i)=>{ if(i===0) ctx.moveTo(p.x,p.y); else ctx.lineTo(p.x,p.y); });
      ctx.strokeStyle=ds.borderColor||'#22c55e';
      ctx.lineWidth=ds.borderWidth||2;
      ctx.stroke();

      if(ds.fill){
        ctx.lineTo(points[points.length-1].x,bottom);
        ctx.lineTo(points[0].x,bottom);
        ctx.closePath();
        ctx.fillStyle=typeof ds.backgroundColor==='string'?ds.backgroundColor:hexToRgba(ds.borderColor,0.12);
        ctx.fill();
      }
      ctx.restore();

      const pointRadius=Number(ds.pointRadius||2);
      ctx.fillStyle=ds.pointBackgroundColor||ds.borderColor||'#22c55e';
      points.forEach((p)=>{
        ctx.beginPath();
        ctx.arc(p.x,p.y,pointRadius,0,Math.PI*2);
        ctx.fill();
      });

      this._runPlugins();
    }

    _runPlugins(){
      for(const plugin of this.plugins){
        try{ plugin?.afterDatasetsDraw?.(this); }catch(_e){}
      }
    }

    _eventPos(evt){
      const rect=this.canvas.getBoundingClientRect();
      const touch=evt.touches?.[0]||evt.changedTouches?.[0];
      const clientX=touch?touch.clientX:evt.clientX;
      const clientY=touch?touch.clientY:evt.clientY;
      return {x:clientX-rect.left,y:clientY-rect.top};
    }

    _onMove(evt){
      if(!this._points.length) return;
      const pos=this._eventPos(evt);
      let nearest=null;
      let best=Infinity;
      this._points.forEach((p,i)=>{
        const d=Math.hypot(p.x-pos.x,p.y-pos.y);
        if(d<best){ best=d; nearest={element:p,index:i,datasetIndex:0}; }
      });
      const active=(nearest&&nearest.element.x>=this.chartArea.left&&nearest.element.x<=this.chartArea.right)?[nearest]:[];
      this._activeElements=active;
      this.tooltip._active=active;
      for(const plugin of this.plugins){
        try{ plugin?.afterEvent?.(this,{event:evt}); }catch(_e){}
      }
      const external=this.options?.plugins?.tooltip?.external;
      if(typeof external==='function'){
        try{ external({chart:this,tooltip:this.tooltip}); }catch(_e){}
      }
      this._draw();
      if(active[0]){
        const p=active[0].element;
        const ctx=this.ctx;
        const radius=clamp(Number(this._dataset().pointHoverRadius||4),2,12);
        ctx.save();
        ctx.beginPath();
        ctx.fillStyle=this._dataset().borderColor||'#22c55e';
        ctx.arc(p.x,p.y,radius,0,Math.PI*2);
        ctx.fill();
        ctx.restore();
      }
    }

    _clearActive(){
      this._activeElements=[];
      this.tooltip._active=[];
      for(const plugin of this.plugins){
        try{ plugin?.afterEvent?.(this,{event:null}); }catch(_e){}
      }
      const external=this.options?.plugins?.tooltip?.external;
      if(typeof external==='function'){
        try{ external({chart:this,tooltip:this.tooltip}); }catch(_e){}
      }
      this._draw();
    }
  }

  window.Chart = MiniChart;
})();
